INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0cfa6ade-301b-4e22-8280-dc5fa3c32a1f',
  '00000000-0000-0000-0000-000000000001',
  $escape$Cassandra's Place in the Database Landscape — Wide-Column, OLTP, and Where It Breaks$escape$,
  $escape$Cassandra sits firmly in the wide-column category — not relational, not document, not a search engine. Its data model forces you to design tables around queries, not entities. Every table has a partition key (the distribution unit) and optional clustering columns (the sort order within a partition). There are no joins, no foreign keys, and no ad-hoc GROUP BY analytics.

This makes Cassandra excellent for high-cardinality, write-heavy OLTP patterns — IoT event streams, audit logs, user activity tracking — where access patterns are known upfront. TWCS (TimeWindowCompactionStrategy) is purpose-built for time-bounded data, grouping SSTables by time window for efficient TTL expiry.

But Cassandra is a poor fit for OLAP. It has no native aggregation pushdown, no columnar storage, and full-partition scans are expensive. For analytics, pair it with Spark via the DataStax Spark Connector, or export to a columnar store like ClickHouse. Lightweight transactions (IF NOT EXISTS over PAXOS) give limited OLTP-style guarantees but at steep latency cost — avoid them unless truly necessary. Know the shape of your reads before you model anything.$escape$,
  $escape$-- Wide-column: design tables around queries, not entities
CREATE TABLE user_activity_by_day (
    user_id   UUID,
    day       DATE,
    event_time TIMESTAMP,
    event_type TEXT,
    metadata  MAP<TEXT, TEXT>,
    PRIMARY KEY ((user_id, day), event_time)
) WITH CLUSTERING ORDER BY (event_time DESC)
   AND compaction = {
    'class': 'TimeWindowCompactionStrategy',
    'compaction_window_unit': 'DAYS',
    'compaction_window_size': 1
   }
   AND default_time_to_live = 2592000;$escape$,
  $escape$sql$escape$,
