INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '400e1316-5194-4f20-adf7-627baf16188b',
  '00000000-0000-0000-0000-000000000001',
  $escape$Cassandra Dev's Field Guide to PostgreSQL — ACID, JSONB, Partitioning, and pgvector$escape$,
  $escape$Cassandra's partition-first model makes PostgreSQL's feature set feel inverted. Where Cassandra defers consistency for availability, Postgres enforces ACID by default — every write is durable via WAL, with BEGIN/COMMIT blocks replacing Cassandra's lightweight transactions (LWT). Rollbacks are real; compensating writes are not needed.

Indexes in Postgres are global B-tree structures, unlike Cassandra's secondary indexes that scatter across nodes and trigger coordinator fan-out. Run EXPLAIN ANALYZE religiously; a seq scan on 10M rows hits the same way a Cassandra full-table scan does.

JSONB is Cassandra's map<text, text> on steroids: binary-stored, indexable via GIN, and queryable with -> and @> operators. You can enforce partial schema with check constraints — something Cassandra's schema-less maps cannot do.

Postgres PARTITION BY RANGE/LIST/HASH is a storage optimization on a single node — not a distribution strategy. Don't map it to Cassandra's partition key; they solve different problems.

pgvector adds vector(384) columns with <-> (L2), <=> (cosine), and <#> (inner product) operators. Index with ivfflat or hnsw for ANN search — semantic capabilities that Cassandra requires external tooling to reach.$escape$,
  $escape$-- JSONB with GIN index (richer than Cassandra map<text,text>)
CREATE TABLE tech_docs (
  id        UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  metadata  JSONB NOT NULL,
  embedding vector(384)
);

CREATE INDEX idx_meta_gin  ON tech_docs USING GIN (metadata);
CREATE INDEX idx_vec_hnsw  ON tech_docs USING hnsw (embedding vector_cosine_ops);

-- Filter by JSONB field + nearest-neighbor vector search in one query
SELECT id, metadata->>'title' AS title
FROM   tech_docs
