INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '27b0e83a-9f28-4468-a36b-df1a7d76ba97',
  '00000000-0000-0000-0000-000000000001',
  $escape$Cassandra Partition Key Design — Model for Queries, Not Entities$escape$,
  $escape$Cassandra's storage engine organizes data into partitions, and every read must target a specific partition key. Unlike relational databases, you design tables around access patterns first — the query defines the schema. A wide row stores all columns sharing the same partition key contiguously on disk, making range scans within a partition blazing fast. But oversized partitions (>100MB) cause GC pressure and compaction hotspots. Use a composite partition key like `(user_id, bucket)` to spread write load when cardinality is uneven.

Every write in Cassandra is a timestamped upsert — last-write-wins (LWW) via HLC. With `LOCAL_QUORUM`, you get strong consistency within a datacenter at the cost of latency; `ONE` maximizes availability but risks stale reads during node failure. Tombstones accumulate on deletes and slow down reads until compaction purges them — set `gc_grace_seconds` appropriately and avoid deleting from high-volume partitions. For time-series data, bucket by time period in the partition key to bound partition growth and enable TTL-driven expiry.$escape$,
  $escape$-- Model: fetch a user's activity feed, newest first
CREATE TABLE activity_feed (
  user_id   UUID,
  bucket    INT,          -- e.g. YYYYMM to cap partition size
  event_ts  TIMEUUID,     -- type-1 UUID preserves insert order
  payload   TEXT,
  PRIMARY KEY ((user_id, bucket), event_ts)
) WITH CLUSTERING ORDER BY (event_ts DESC)
  AND default_time_to_live = 2592000  -- 30-day TTL
  AND compaction = {
    'class': 'TimeWindowCompactionStrategy',
    'compaction_window_unit': 'DAYS',
    'compaction_window_size': 1
  };$escape$,
  $escape$sql$escape$,
