INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '26e74718-7a3b-45ec-b840-e5125ec814f3',
  '00000000-0000-0000-0000-000000000001',
  $escape$Cassandra vs DynamoDB — Single Table Design, Sort Keys, GSIs, and Capacity Modes Decoded$escape$,
  $escape$DynamoDB's single-table design mirrors Cassandra's query-first modeling — both reject normalization to co-locate access patterns. DynamoDB's partition key hashes identically to Cassandra's partition key: same node-routing semantics, same hot-partition risks. The sort key is Cassandra's clustering column — it orders rows within a partition and enables `WHERE sk BETWEEN :a AND :b` range scans. Unlike Cassandra's multi-column clustering keys, DynamoDB restricts you to one sort key, forcing the overloaded-key pattern (`USER#123`, `POST#456`) to pack multiple entity types into one table — a pattern CQL avoids by simply creating separate tables per query.

DynamoDB LSIs extend the sort key on an alternate attribute within the same partition — conceptually close to a secondary clustering column. GSIs replicate data under a new partition key and sort key, making them analogous to Cassandra Materialized Views: both incur write amplification and eventual consistency lag.

Capacity modes are where the models diverge sharply. DynamoDB's provisioned RCU/WCU and on-demand billing have no CQL equivalent — Cassandra provisions physical nodes, not logical throughput tokens. When comparing costs, map DynamoDB read units to Cassandra's LOCAL_QUORUM read latency budget, not to any billing abstraction.$escape$,
  $escape$-- DynamoDB single-table "Users + Posts" expressed in idiomatic Cassandra CQL

CREATE TABLE user_posts (
    user_id  UUID,
    created_at TIMESTAMP,   -- clustering col == DynamoDB sort key
    post_id  UUID,
    content  TEXT,
    PRIMARY KEY (user_id, created_at)
) WITH CLUSTERING ORDER BY (created_at DESC);

-- DynamoDB GSI on post_id  →  Cassandra Materialized View
CREATE MATERIALIZED VIEW posts_by_id AS
    SELECT * FROM user_posts
    WHERE post_id IS NOT NULL
      AND user_id IS NOT NULL
      AND created_at IS NOT NULL
    PRIMARY KEY (post_id, user_id, created_at);$escape$,
