INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '61e68d73-f391-496e-87f1-b4424b6ce8a9',
  '00000000-0000-0000-0000-000000000001',
  $escape$Cassandra + Elasticsearch — Adding Full-Text Search to Your Cassandra Data Model$escape$,
  $escape$Cassandra excels at high-throughput writes and partition-key lookups, but CQL has no full-text search. Pairing Cassandra with Elasticsearch is the standard pattern: Cassandra owns primary storage and write throughput; ES owns search.

ES stores data in an inverted index — each unique token maps to the documents containing it, the inverse of Cassandra's SSTable row-key structure. Defining an index mapping is analogous to a CQL CREATE TABLE, but field types control search behavior: keyword behaves like a Cassandra partition key (exact match only), while text fields are passed through an analyzer pipeline — tokenizer → character filters → token filters — at both index and query time. No CQL equivalent exists.

The Query DSL replaces CQL for search: bool queries compose must/should/filter/must_not clauses, giving AND/OR/NOT semantics without the ALLOW FILTERING penalty. Aggregations fill the GROUP BY gap — terms aggregations bucket counts across keyword fields while metric aggregations (avg, percentiles) operate on numerics.

Sync rows from Cassandra using the DataStax Kafka Connector or Debezium CDC → Kafka → Logstash. Treat ES as a read-only search replica; never use it as your source of truth.$escape$,
  $escape$from elasticsearch import Elasticsearch

es = Elasticsearch("http://localhost:9200")

es.indices.create(index="tech_events", body={
    "mappings": {
        "properties": {
            "event_id":  {"type": "keyword"},
            "payload":   {"type": "text", "analyzer": "english"},
            "timestamp": {"type": "date"},
            "severity":  {"type": "keyword"}
        }
    }
})

# Sync a Cassandra row into ES
es.index(index="tech_events", id="abc-123", document={
    "event_id": "abc-123",
    "payload": "Cassandra compaction triggered on dc1-node3",
    "timestamp": "2026-04-16T10:00:00Z",
    "severity": "warn"
})

# Bool query + bucket aggregation — no CQL equivalent
result = es.search(index="tech_events", body={
    "query": {
        "bool": {
            "must":   {"match":  {"payload": "compaction"}},
            "filter": {"term":   {"severity": "warn"}}
        }
    },
    "aggs": {
        "by_severity": {"terms": {"field": "severity"}}
    }
})$escape$,
