INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4b28b07a-c65d-40ad-a5a4-e377350273b1',
  '00000000-0000-0000-0000-000000000001',
  $escape$Cassandra to ClickHouse — Trading LSM Writes for Columnar OLAP Speed$escape$,
  $escape$Cassandra's write-optimized LSM-tree model excels at high-throughput ingestion but struggles with analytical aggregations — full-partition scans are expensive, and cross-partition queries require application-side scatter/gather. ClickHouse solves this with columnar MergeTree storage: only the columns touched by a query are read from disk, making GROUP BY and aggregations dramatically faster.

Cassandra developers will recognize the ORDER BY clause in MergeTree DDL — it functions like your partition key + clustering columns, controlling physical sort order and enabling sparse primary index lookups. Unlike Cassandra's SSTable compaction strategies (STCS/LCS/TWCS), MergeTree merges parts in the background and can apply transformation logic during merge via specialized engines like SummingMergeTree or AggregatingMergeTree.

Where Cassandra materialized views require careful capacity planning and lag under write pressure, ClickHouse materialized views are insert-triggered — they process data synchronously at ingest and persist pre-aggregated results into a separate MergeTree table. This eliminates the dual-write pattern Cassandra developers typically implement at the application layer to support analytical read paths.$escape$,
  $escape$-- Cassandra: denormalized wide-column, write-optimized
-- PRIMARY KEY (user_id, event_time) controls partition + clustering

-- ClickHouse MergeTree equivalent — columnar, OLAP-optimized
CREATE TABLE events (
    user_id     UUID,
    event_time  DateTime,
    event_type  String,
    payload     String
) ENGINE = MergeTree()
ORDER BY (user_id, event_time);

-- Materialized view: pre-aggregate at ingest (no app-side dual-write needed)
CREATE MATERIALIZED VIEW events_hourly_mv
ENGINE = SummingMergeTree()
ORDER BY (event_type, hour)
AS SELECT
    event_type,
    toStartOfHour(event_time) AS hour,
    count()                   AS cnt
FROM events
GROUP BY event_type, hour;$escape$,
