INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '26ac2984-af7e-41c3-a4b3-5894a00ec6dc',
  '00000000-0000-0000-0000-000000000001',
  $escape$Cassandra vs TimescaleDB — Hypertables, Continuous Aggregates, and What You'd Replace$escape$,
  $escape$Cassandra developers typically hand-roll time-bucketing into partition keys (e.g., `(sensor_id, date)`) to avoid unbounded wide partitions. TimescaleDB automates this with hypertables — a PostgreSQL table transparently partitioned by a `time` column into configurable chunks. No manual bucket logic leaking into your schema design.

Where Cassandra forces you to maintain separate rollup tables — usually via Spark jobs or application-level writes — TimescaleDB offers continuous aggregates: incremental, auto-refreshed materialized views using `CREATE MATERIALIZED VIEW ... WITH (timescaledb.continuous)`. Only newly ingested chunks trigger recomputation, not full scans.

Cassandra's SSTable-level compression (LZ4/Snappy) reduces storage but keeps row-oriented layout. TimescaleDB's `add_compression_policy()` converts older chunks to columnar storage, yielding 90–95% reduction on repetitive sensor data — compressed chunks remain fully queryable inline.

For range queries, `time_bucket('1 hour', recorded_at)` replaces your partition-key bucket logic with a SQL-native function. Pair it with a continuous aggregate and you skip full chunk scans entirely. The trade-off is real: Cassandra's raw write throughput at scale still wins. TimescaleDB earns its place when analytics and ingestion must coexist on the same dataset.$escape$,
  $escape$-- Replaces manual (sensor_id, date) composite partition key
SELECT create_hypertable('sensor_readings', 'recorded_at',
  chunk_time_interval => INTERVAL '1 day');

-- Replaces Spark rollup jobs — incremental, auto-refreshed
CREATE MATERIALIZED VIEW hourly_avg
WITH (timescaledb.continuous) AS
SELECT sensor_id,
       time_bucket('1 hour', recorded_at) AS bucket,
       AVG(value) AS avg_value
FROM sensor_readings
GROUP BY sensor_id, bucket;

-- Refresh policy (no external scheduler needed)
SELECT add_continuous_aggregate_policy('hourly_avg',
  start_offset      => INTERVAL '3 hours',
  end_offset        => INTERVAL '1 hour',
  schedule_interval => INTERVAL '1 hour');

-- Columnar compression on chunks older than 7 days (~90% reduction)
SELECT add_compression_policy('sensor_readings', INTERVAL '7 days');$escape$,
