INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '1fe8d196-349c-4404-bb35-bbcfa9d59209',
  '00000000-0000-0000-0000-000000000001',
  $escape$Cassandra Indexing Strategy — Hashing, SAI, and When to Denormalize$escape$,
  $escape$Cassandra's partition key uses Murmur3 hashing — equality-only, zero range support. Clustering columns are your B-tree analogue: sorted within a partition, enabling efficient range queries via CLUSTERING ORDER BY.

For non-primary-key lookups, legacy secondary indexes (2i) fan out to every node — avoid them on high-cardinality columns. SAI (Storage-Attached Indexing) is the modern replacement: compaction-aware, co-located with SSTables, supporting both equality and range predicates on arbitrary columns. Enable token-based text matching via SAI's analyzer config — Cassandra's closest equivalent to GIN. Bloom filters embedded in each SSTable act as a BRIN-style skip structure, letting reads bypass irrelevant data files without touching them.

There's no native partial index, but scoping a SAI query with a partition key predicate achieves similar selectivity at query time. For covering-index behavior, Cassandra still demands denormalization: model a second table whose primary key matches the query's access pattern. SAI reduces the frequency, but query-first schema design remains the primary performance lever.$escape$,
  $escape$-- Partition key: Murmur3 hash → equality only
-- Clustering key: sorted → supports range queries
CREATE TABLE user_events (
  user_id   uuid,
  occurred  timestamp,
  category  text,
  PRIMARY KEY (user_id, occurred)
) WITH CLUSTERING ORDER BY (occurred DESC);

-- SAI: equality + range on non-PK column (replaces legacy 2i)
CREATE CUSTOM INDEX idx_category
  ON user_events (category)
  USING 'StorageAttachedIndex';

-- Scoped query: partition key + clustering range + SAI filter
SELECT * FROM user_events
WHERE user_id = ? AND occurred > ? AND category = ?;$escape$,
  $escape$sql$escape$,
