INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '062afdaa-8c00-4d4c-b3a7-8d979128e607',
  '00000000-0000-0000-0000-000000000001',
  $escape$Cassandra Partitioning — Shard Key Design and Avoiding Hot Spots$escape$,
  $escape$Cassandra's 'sharding' is consistent hashing: the Murmur3Partitioner maps every partition key to a token in the [-2^63, 2^63) range. Each node owns token ranges; a row always lands on the node responsible for its token. Vnodes (num_tokens, default 256 per node) subdivide those ranges automatically — no manual shard assignment needed.

The real danger is partition key design. Using event_date as a partition key funnels every today-write to one token, creating a hot node that degrades cluster-wide throughput. A composite key like (user_id, month) distributes load by user while capping per-partition row count. Keep partitions under 100 MB — beyond that, GC pressure and compaction latency climb sharply. Monitor with nodetool tablestats or query system.size_estimates to catch bloated partitions early.

For time-series, bucket explicitly: pre-compute a truncated time unit (hour, day) and embed it in the composite partition key. This bounds partition growth and ensures reads hit multiple nodes. Never use a monotonically increasing value (auto-increment ID, raw timestamp) as a standalone partition key — it serializes writes to a single token range indefinitely.$escape$,
  $escape$-- BAD: single date key → all today's writes hit one token
CREATE TABLE events_bad (
  event_date date,
  event_id uuid,
  payload text,
  PRIMARY KEY (event_date, event_id)
);

-- GOOD: composite key spreads load, bounds partition size
CREATE TABLE events_good (
  user_id uuid,
  month text,
  event_id timeuuid,
  payload text,
  PRIMARY KEY ((user_id, month), event_id)
) WITH CLUSTERING ORDER BY (event_id DESC);$escape$,
