INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e60711f4-d9d4-449c-a7e9-2404906456ef',
  '00000000-0000-0000-0000-000000000001',
  $escape$Cassandra Connection Pooling — Driver-Native Pool Sizing and Tuning$escape$,
  $escape$Cassandra's drivers handle connection pooling natively — no PgBouncer equivalent exists or is needed. Each driver maintains a pool per host, bucketed by `HostDistance` (LOCAL vs REMOTE). Unlike PostgreSQL, where one backend process owns one connection, Cassandra's native protocol v3+ multiplexes requests over a single TCP connection using stream IDs — up to 32,768 concurrent streams per connection.

The three levers are `core_connections_per_host`, `max_connections_per_host`, and `max_requests_per_connection`. In practice, 1–2 LOCAL connections saturate most workloads; the driver auto-scales toward `max_connections_per_host` only when the pool is full. Oversizing hurts — every connection spawns a reader thread on the Cassandra node side, increasing GC pressure and contention on the `io_global_order` stage.

The default `max_requests_per_connection` is 1024. On low-latency intra-DC networks, raising it to 2048 improves throughput without adding connections. Keep `remote_connections_per_host` at 0 unless you're explicitly routing cross-DC fallback reads — unnecessary remote connections inflate coordinator latency and waste LOCAL thread budget on remote nodes.$escape$,
  $escape$from cassandra.cluster import Cluster
from cassandra.policies import DCAwareRoundRobinPolicy
from cassandra.pool import HostDistance

cluster = Cluster(
    contact_points=['10.0.0.1'],
    load_balancing_policy=DCAwareRoundRobinPolicy(local_dc='datacenter1'),
)

cluster.set_core_connections_per_host(HostDistance.LOCAL, 1)
cluster.set_max_connections_per_host(HostDistance.LOCAL, 4)
cluster.set_max_requests_per_connection(HostDistance.LOCAL, 2048)
cluster.set_core_connections_per_host(HostDistance.REMOTE, 0)
cluster.set_max_connections_per_host(HostDistance.REMOTE, 0)

session = cluster.connect('my_keyspace')$escape$,
  $escape$python$escape$,
