INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '133dc461-5b0e-429e-ae94-09be56cf7afd',
  '00000000-0000-0000-0000-000000000001',
  $escape$Cassandra Monitoring — Slow Queries, Hints, Connections, and Storage$escape$,
  $escape$Cassandra exposes operational health through JMX metrics and `nodetool` — there is no built-in dashboard. For slow queries, set `slow_query_log_timeout_in_ms: 500` in `cassandra.yaml`; queries exceeding the threshold are written to `system.log`. For deeper inspection, use `nodetool settraceprobability 0.01` to sample 1% of requests into `system_traces.sessions` and `system_traces.events`, queryable via CQL.

Connection counts surface through JMX at `org.apache.cassandra.metrics:type=Client,name=connectedNativeClients`. Sustained counts approaching `native_transport_max_threads` indicate driver pool saturation.

Cassandra has no MySQL-style replication lag. The equivalent signal is hint accumulation: `nodetool tpstats` shows `HintedHandoffManager` pending tasks. A rising count means a replica is unreachable and writes are being queued for replay. If a node stays down past `max_hint_window_in_ms` (default 3 hours), hints are discarded and a full repair is required.

Storage growth is tracked per-table via `nodetool tablestats`. Watch `Live disk space used` and `SSTable count` — a climbing SSTable count with stalled compaction means I/O pressure. Cross-reference with `nodetool compactionstats` and tune `concurrent_compactors` accordingly.$escape$,
  $escape$# Enable slow query logging — cassandra.yaml
# slow_query_log_timeout_in_ms: 500

# Sample 1% of queries into system_traces
nodetool settraceprobability 0.01

# Connected native transport clients
nodetool tpstats | grep -E "NativeTransport"

# Hint backlog — proxy for replication lag
nodetool tpstats | grep -A3 "HintedHandoff"

# Per-table disk usage and SSTable count
nodetool tablestats mykeyspace.mytable | grep -E "Live disk|SSTable count"

# Active compaction progress
nodetool compactionstats$escape$,
  $escape$bash$escape$,
